PREAMBLES = [
    "\u26A0\uFE0F <b>\u0410\u043D\u0442\u0438\u0441\u043E\u0432\u0435\u0442 \u0434\u043D\u044F</b>",
    "\U0001F6AB <b>\u0412\u0440\u0435\u0434\u043D\u044B\u0439 \u0441\u043E\u0432\u0435\u0442 \u0434\u043D\u044F</b>",
    "\U0001F4A1 <b>\u0411\u0435\u0441\u043F\u043E\u043B\u0435\u0437\u043D\u044B\u0439 \u0441\u043E\u0432\u0435\u0442 \u043D\u0430 \u0441\u0435\u0433\u043E\u0434\u043D\u044F</b>",
    "\U0001F3AF <b>\u0427\u0435\u0433\u043E \u0434\u0435\u043B\u0430\u0442\u044C \u043D\u0435 \u043D\u0430\u0434\u043E</b>",
]


def generate_anti_advice(count: int = 5) -> str:
    preamble = random.choice(PREAMBLES)
    selected = random.sample(ANTI_ADVICE, min(count, len(ANTI_ADVICE)))
    lines = "\n\n".join(f"\u2022 {a}" for a in selected)
    return (
        f"{preamble}\n\n"
        f"{lines}\n\n"
        f"\U0001F447 \u041F\u043E\u0434\u043F\u0438\u0448\u0438\u0441\u044C \u043D\u0430 @Anetdodik "
        f"\u2014 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u043D\u043E\u0432\u044B\u0439 \u0430\u043D\u0442\u0438\u0441\u043E\u0432\u0435\u0442!"
    )
